import { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { Chart } from 'react-chartjs-2';
import { useAuth } from '../hooks/useAuth';
import { fetchDashboardData } from '../utils/api';

const Dashboard = () => {
  const { user } = useAuth();
  const [dashboardData, setDashboardData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadDashboardData = async () => {
      try {
        const data = await fetchDashboardData();
        setDashboardData(data);
      } catch (err) {
        setError('Failed to load dashboard data.');
      } finally {
        setLoading(false);
      }
    };
    loadDashboardData();
  }, []);

  if (loading) return <div className="text-white">Loading...</div>;
  if (error) return <div className="text-red-500">{error}</div>;

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">
      <h1 className="text-3xl font-bold text-white mb-6">Welcome, {user.name}</h1>
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-xl font-semibold text-white">Total Sales</h2>
          <p className="text-2xl text-indigo-400">${dashboardData.totalSales}</p>
        </div>
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-xl font-semibold text-white">Active Users</h2>
          <p className="text-2xl text-indigo-400">{dashboardData.activeUsers}</p>
        </div>
        <div className="bg-gray-800 p-6 rounded-xl shadow-md">
          <h2 className="text-xl font-semibold text-white">Inventory Levels</h2>
          <p className="text-2xl text-indigo-400">{dashboardData.inventoryLevels}</p>
        </div>
      </div>
      <div className="mt-8">
        <h2 className="text-2xl font-semibold text-white mb-4">Sales Overview</h2>
        <Chart
          type="line"
          data={dashboardData.salesChartData}
          options={{ maintainAspectRatio: false }}
        />
      </div>
    </div>
  );
};

export default Dashboard;

