import { useState, useEffect } from 'react';
import { fetchProducts, deleteProduct } from '../utils/api';
import { Product } from '../types';

const ProductList = () => {
  const [products, setProducts] = useState<Product[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  useEffect(() => {
    const loadProducts = async () => {
      try {
        const data = await fetchProducts();
        setProducts(data);
      } catch (err) {
        setError('Failed to load products.');
      } finally {
        setLoading(false);
      }
    };
    loadProducts();
  }, []);

  const handleDelete = async (productId: string) => {
    try {
      await deleteProduct(productId);
      setProducts(products.filter(product => product.id !== productId));
    } catch (err) {
      setError('Failed to delete product.');
    }
  };

  if (loading) return <div className="text-white">Loading...</div>;
  if (error) return <div className="text-red-500">{error}</div>;

  return (
    <div className="max-w-6xl mx-auto px-4 py-6">
      <h1 className="text-3xl font-bold text-white mb-6">Product Management</h1>
      <table className="min-w-full bg-gray-800 rounded-xl">
        <thead>
          <tr>
            <th className="text-left text-white p-4">Name</th>
            <th className="text-left text-white p-4">Price</th>
            <th className="text-left text-white p-4">Stock</th>
            <th className="text-left text-white p-4">Actions</th>
          </tr>
        </thead>
        <tbody>
          {products.map(product => (
            <tr key={product.id} className="border-b border-gray-700">
              <td className="text-white p-4">{product.name}</td>
              <td className="text-white p-4">${product.price}</td>
              <td className="text-white p-4">{product.stock}</td>
              <td className="text-white p-4">
                <button
                  onClick={() => handleDelete(product.id)}
                  className="px-4 py-2 rounded-lg bg-red-600 text-white hover:bg-red-500 transition"
                >
                  Delete
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

export default ProductList;
